Still think 1D kernel is more efficient

```c
// launch with 1D, NormalizeBackwardCudaKernel<gpu, DType>
//        <<<blocks, dim3(cuda::kMaxThreadsPerBlock, 1), 0, stream>>>(out_grad, in_grad,
//            req, N, H, W, C, std_d0, std_d1, std_d2);
template<typename xpu, typename DType>
__global__ void
__launch_bounds__(cuda::kMaxThreadsPerBlock, 1)
NormalizeBackwardCudaKernel(const Tensor<xpu, 3, DType> out_grad,
                            const Tensor<xpu, 3, DType> in_grad,
                            const int req,
                            const int N,
                            const int H,
                            const int W,
                            const int C,
                            const float std_d0,
                            const float std_d1,
                            const float std_d2) {
    for (int i = threadIdx.x; i < H * W * C; ++threadIdx.x) {
        float std = std_d0;
        int c = i % 3;
        switch (c) {
            case 0 : break;
            case 1 : std = std_d1;
                     break;
            case 2 : std = std_d2;
                     break;
        KERNEL_ASSIGN(*(in_grad.data_ + i), req,
                              *(out_grad.data_ + i) * (1 / std));
        }
    }
}
```

